import { useEvent } from "../hooks/use-event.js";
export function useRowAdd(props) {
    const rowAdd = useEvent((rows, index) => {
        props.onRowsAdded?.({
            newData: rows,
            placement: index ?? "start",
            top: props.topData ?? [],
            center: props.data ?? [],
            bottom: props.bottomData ?? [],
        });
    });
    return rowAdd;
}
